export function getCityData(slug: string): CityData | null {
  return cityData[slug] || null
}

/**
 * Primary money page for a city (R1/R4). Falls back to 'tmcp' — the highest-LTV
 * default we steer city visitors toward. The city template reads this to
 * emphasise the matching service card.
 */
export function getCityPrimaryMoneyPage(slug: string): MoneyPage {
  return getCityData(slug)?.primaryMoneyPage ?? 'tmcp'
}

export function getAllCitySlugs(): string[] {
  return Object.keys(cityData)
}

/**
 * Return the N geographically nearest cities to the given slug, ranked by
 * Euclidean distance on lat/lng (fine for cross-city ranking at this scale —
 * no need for haversine over a ~100-mile service area).
 *
 * Used by city pages to render 5-6 nearby-city links. SearchPilot's A/B test
 * found +7% organic traffic from linking to 6 nearest neighbouring location
 * pages (vs 2). Replaces the hand-picked nearbyCity1/nearbyCity2 fields.
 */
export function getNearestCities(
  slug: string,
  count: number = 6,
): { name: string; slug: string; county: string }[] {
  const origin = cityData[slug]
  if (!origin) return []

  const oLat = parseFloat(origin.lat)
  const oLng = parseFloat(origin.lng)

  return Object.values(cityData)
    .filter((c) => c.slug !== slug)
    .map((c) => {
      const dLat = parseFloat(c.lat) - oLat
      const dLng = parseFloat(c.lng) - oLng
      return { city: c, distSq: dLat * dLat + dLng * dLng }
    })
    .sort((a, b) => a.distSq - b.distSq)
    .slice(0, count)
    .map(({ city }) => ({ name: city.name, slug: city.slug, county: city.county }))
}



